// Message Normalizer: Extract common format from platform-specific payloads
const raw = $input.item.json.body || $input.item.json;
const now = new Date().toISOString();

// If already normalized (has platform_source), pass through with defaults
if (raw.platform_source && raw.sender_id && raw.message_text) {
  return [{
    json: {
      platform_source: raw.platform_source,
      channel_id: raw.channel_id || raw.channel || null,
      sender_id: raw.sender_id,
      sender_email: raw.sender_email || null,
      message_text: raw.message_text,
      attachments: raw.attachments || [],
      timestamp: raw.timestamp || now,
      thread_id: raw.thread_id || raw.thread_ts || null
    }
  }];
}

// Slack Events API
if (raw.event?.type === 'app_mention' || raw.event?.type === 'message' || raw.event?.channel) {
  const ev = raw.event;
  return [{
    json: {
      platform_source: 'slack',
      channel_id: ev.channel || null,
      sender_id: ev.user || ev.bot_id || 'unknown',
      sender_email: ev.user_profile?.email || null,
      message_text: ev.text || ev.message?.text || '',
      attachments: ev.files || [],
      timestamp: ev.ts ? new Date(parseFloat(ev.ts) * 1000).toISOString() : now,
      thread_id: ev.thread_ts || null
    }
  }];
}

// Discord webhook payload
if (raw.author?.id || raw.channel_id) {
  return [{
    json: {
      platform_source: 'discord',
      channel_id: raw.channel_id || null,
      sender_id: raw.author?.id || raw.member?.user?.id || 'unknown',
      sender_email: null,
      message_text: raw.content || '',
      attachments: raw.attachments || [],
      timestamp: raw.timestamp || now,
      thread_id: raw.thread?.id || null
    }
  }];
}

// Evolution API (WhatsApp) webhook
if (raw.key?.remoteJid || raw.from) {
  const from = raw.key?.remoteJid || raw.from;
  const msg = raw.message?.conversation || raw.message?.extendedTextMessage?.text || raw.body?.message || '';
  return [{
    json: {
      platform_source: 'whatsapp',
      channel_id: from,
      sender_id: from,
      sender_email: null,
      message_text: msg,
      attachments: [],
      timestamp: now,
      thread_id: null
    }
  }];
}

// signal-cli REST webhook
if (raw.envelope?.source || raw.dataMessage) {
  const src = raw.envelope?.source || raw.source || 'unknown';
  const txt = raw.dataMessage?.message || raw.envelope?.dataMessage?.message || '';
  return [{
    json: {
      platform_source: 'signal',
      channel_id: src,
      sender_id: src,
      sender_email: null,
      message_text: txt,
      attachments: [],
      timestamp: now,
      thread_id: null
    }
  }];
}

// Gmail / email payload
if (raw.from?.address || raw.sender) {
  const addr = raw.from?.address || raw.from || raw.sender;
  const subj = raw.subject || '';
  const body = raw.snippet || raw.body || raw.textPlain || '';
  return [{
    json: {
      platform_source: 'email',
      channel_id: null,
      sender_id: addr,
      sender_email: addr,
      message_text: subj ? `${subj}\n\n${body}` : body,
      attachments: raw.attachments || [],
      timestamp: raw.internalDate ? new Date(parseInt(raw.internalDate)).toISOString() : now,
      thread_id: raw.threadId || null
    }
  }];
}

// Asana webhook
if (raw.resource?.gid || raw.events) {
  const evts = raw.events || [raw];
  const first = Array.isArray(evts) ? evts[0] : evts;
  const resource = first?.resource || raw.resource || {};
  return [{
    json: {
      platform_source: 'asana',
      channel_id: resource.gid || null,
      sender_id: first?.user?.gid || resource.gid || 'unknown',
      sender_email: first?.user?.email || null,
      message_text: resource.name || JSON.stringify(resource),
      attachments: [],
      timestamp: now,
      thread_id: resource.gid || null
    }
  }];
}

// Fallback: treat as generic with platform from body or query
const platform = raw.platform || raw.platform_source || 'unknown';
return [{
  json: {
    platform_source: platform,
    channel_id: raw.channel_id || raw.channel || null,
    sender_id: raw.sender_id || raw.user_id || raw.user || 'unknown',
    sender_email: raw.sender_email || null,
    message_text: raw.message_text || raw.text || raw.message || JSON.stringify(raw),
    attachments: raw.attachments || [],
    timestamp: raw.timestamp || now,
    thread_id: raw.thread_id || null
  }
}];

// Merge normalized message with verify response for orchestrator
const norm = $('Message Normalizer').first().json;
const verify = $('Verify Sender').first().json;
return [{ json: { ...norm, sender_role: verify.role || 'none', sender_email_resolved: verify.email || norm.sender_email } }];
